-- Get user info
SET @user_id = (SELECT id FROM users LIMIT 1);
SET @org_id = (SELECT organization_id FROM users WHERE id = @user_id);

-- Insert test project
INSERT INTO projects (name, code, organization_id, totalBudget, spentBudget, status, createdAt, updatedAt)
VALUES ('Test Invoice Project', 'TEST-INV-005', @org_id, 10000.00, 0.00, 'active', NOW(), NOW())
ON DUPLICATE KEY UPDATE name = name;

SET @project_id = (SELECT id FROM projects WHERE code = 'TEST-INV-005' LIMIT 1);

-- Insert completed session
INSERT INTO sessions (
  projectId, title, venue, startTime, endTime, status, approvalStatus,
  paymentPerFacilitator, organization_id, createdAt, updatedAt
) VALUES (
  @project_id, 'Test Session for Invoice', 'Test Venue',
  DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY) + INTERVAL 1 HOUR,
  'completed', 'approved', 75.00, @org_id, NOW(), NOW()
);

SET @session_id = LAST_INSERT_ID();

-- Add facilitator
INSERT INTO session_facilitators (sessionId, userId, createdAt)
VALUES (@session_id, @user_id, NOW());

-- Record attendance
INSERT INTO attendance (
  sessionId, userId, joinedAt, leftAt, durationMinutes, wasLate,
  calculatedPayment, organization_id, createdAt, updatedAt
) VALUES (
  @session_id, @user_id, DATE_SUB(NOW(), INTERVAL 1 DAY),
  DATE_SUB(NOW(), INTERVAL 1 DAY) + INTERVAL 1 HOUR,
  60, 0, 75.00, @org_id, NOW(), NOW()
);

-- Verify
SELECT 
  'SUCCESS - Test data created!' as result,
  s.id as session_id,
  s.title,
  s.status,
  s.paymentPerFacilitator as payment,
  a.calculatedPayment as attendance_payment,
  u.name as user_name
FROM sessions s
JOIN attendance a ON s.id = a.sessionId
JOIN users u ON a.userId = u.id
WHERE s.id = @session_id;

